form:Form.form:Scripts:
		function ONLOAD()
{	
	if (Ctrl('main').GetMode() == "EDIT")
	{
		var estadoPadre = Ctrl('estadoPadre').GetCValue();
		var auto = Ctrl('autom').GetCValue()
		if (auto == "1")
		{                              
		  CtrlEnabled('c_estado', false);	
			if (estadoPadre == "S")
			{
				CtrlEnabled('f_descuento'		, true);	
				CtrlEnabled('n_importe'			, true);
				CtrlEnabled('e_cuota'				, true); 
				CtrlEnabled('ADD'						, true); 
				CtrlEnabled('DELETE'				, true); 				
			} else
				{
					CtrlEnabled('f_descuento'	, false);
					CtrlEnabled('n_importe'		, false);
					CtrlEnabled('e_cuota'			, false);
					CtrlEnabled('ADD'					, false);
					CtrlEnabled('DELETE'			, false);
				}
		} else
			{
				if (estadoPadre == "S" || estadoPadre == "O" || estadoPadre == "L" || estadoPadre == "D")
				{
					CtrlEnabled('c_estado'		, true);
					CtrlEnabled('e_cuota'			, true);
					CtrlEnabled('f_descuento'	, true);
					CtrlEnabled('n_importe'		, true);
					CtrlEnabled('ADD'						, true); 
					CtrlEnabled('DELETE'				, true);
				} else
					{                                
						CtrlEnabled('c_estado'		, false);
						CtrlEnabled('e_cuota'			, false);
						CtrlEnabled('f_descuento'	, false);
						CtrlEnabled('n_importe'		, false);					
						CtrlEnabled('ADD'					, false);
						CtrlEnabled('DELETE'			, false);						
					}
		  }
	}

	if (Ctrl('main').GetMode() == "LIST_EDIT")
	{
		var estadoPadre = Ctrl('estadoPadre').GetCValue();
		var auto = Ctrl('autom').GetCValue()
		if (auto == "1")
		{                              
		  CtrlEnabled('c_estado', false);	
			if (estadoPadre == "S")
			{
				CtrlEnabled('ADD'						, true); 
				CtrlEnabled('DELETE'				, true); 				
			} else
				{
					CtrlEnabled('ADD'					, false);
					CtrlEnabled('DELETE'			, false);
				}
		} else
			{
				if (estadoPadre == "S" || estadoPadre == "O" || estadoPadre == "L" || estadoPadre == "D")
				{
					CtrlEnabled('ADD'						, true); 
					CtrlEnabled('DELETE'				, true);
				} else
					{
						CtrlEnabled('ADD'					, false);
						CtrlEnabled('DELETE'			, false);
					}
			}
		}

}
